create table dirkspzm32.s_rcv_dis_to_order (
    s_rcv_dis_to_order_id  number(*, 0) not null enable,
    tour                   varchar2(255 char) not null enable,
    vorgang_id             number(*, 0),
    satzart                varchar2(3 char),
    auftrag                number(*, 5),
    pos_nr                 number(*, 5),
    upos_nr                number(*, 5),
    artikel                varchar2(30 char),
    adr_art                varchar2(1 char),
    adr_nr                 varchar2(20 char),
    adr_liefer             varchar2(20 char),
    leitzahl               number(*, 5),
    charge                 varchar2(60 char),
    seriennr               varchar2(20 char),
    strategie              varchar2(10 char),
    mhd                    date,
    li_nr                  number(*, 5),
    li_pos_nr              number(*, 5),
    arbeitsplatz_id        varchar2(10 char),
    kom_info               varchar2(40 char),
    kom_mg                 number(*, 3),
    kom_mengeneinheit      varchar2(10 char),
    soll_mg                number(*, 3),
    soll_mengeneinheit     varchar2(3 char),
    wa_ziel                varchar2(6 char),
    prioritaet             number(*, 0),
    best_nr_kunde          varchar2(30 char),
    fa_ag                  number(*, 5),
    ziel                   varchar2(30 char),
    anbruch                varchar2(1 char),
    besteller              varchar2(10 char),
    uebert_status          varchar2(3 char),
    fehler_code            number(*, 5),
    fehler_text            varchar2(100 char),
    erstell_datum          date,
    bearb_datum            date,
    quell_lagerorte        varchar2(200 char),
    liefer_datum           date,
    freigabe               varchar2(1 char),
    freigabe_datum         date,
    labor_status           varchar2(1 char),
    konsolidieren          varchar2(1 char),
    ziel_packschema        varchar2(20 char),
    ziel_traeger           varchar2(20 char),
    ueber_unter_liefern    varchar2(4 char),
    komplett_reservieren   varchar2(1 char),
    komplett_bereitstellen varchar2(1 char),
    komm_ganz_gebinde      varchar2(1 char),
    komm_steuerung         varchar2(1 char),
    lam_sel1               varchar2(30 char),
    lam_sel2               varchar2(30 char),
    lam_sel3               varchar2(30 char),
    lam_sel4               varchar2(30 char),
    lam_sel5               varchar2(30 char),
    lam_sel6               varchar2(30 char),
    lam_sel7               varchar2(30 char),
    lam_sel8               varchar2(30 char),
    lam_sel9               varchar2(30 char),
    lam_sel10              varchar2(30 char),
    auf_id                 number(*, 0),
    ziel_traeger_menge     number(*, 3),
    prod_params            varchar2(4000 char)
);

alter table dirkspzm32.s_rcv_dis_to_order
    add constraint pk_s_rcv_dis_to_order primary key ( s_rcv_dis_to_order_id )
        using index enable;


